/**
 * Use Copy to Clipboard component
 *
 * A utility component that provides functionality to copy text to clipboard
 * from HTML elements with specified data attributes
 */
const useCopyToClipboard = () => {
  /**
   * Initialize copy to clipboard functionality on a specific element
   *
   * @param {HTMLElement} element - The element to enable copy to clipboard functionality on
   * @param {string} dataAttribute - The data attribute containing the text to copy (default: 'data-copy-text')
   * @param {string} successMessageAttribute - The data attribute containing the success message (default: 'data-success-message')
   * @param {string} defaultSuccessMessage - Default message to show on successful copy if no data attribute found (default: 'Copied to clipboard')
   * @return {Function} - Cleanup function to remove event listeners
   */
  const initialize = (element, {
    dataAttribute = 'data-copy-text',
    successMessageAttribute = 'data-success-message',
    defaultSuccessMessage = 'Copied to clipboard'
  } = {}) => {
    if (!element) {
      console.warn('useCopyToClipboard: No element provided');
      return () => {};
    }

    const clickHandler = (event) => {
      event.preventDefault();

      const textToCopy = element.getAttribute(dataAttribute);

      if (!textToCopy) {
        console.warn(`useCopyToClipboard: No text found in ${dataAttribute} attribute`);
        return;
      }

      const successMessage = element.getAttribute(successMessageAttribute) || defaultSuccessMessage;

      if (navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(textToCopy)
          .then(() => {
            if (typeof window.showSuccessMessage === 'function') {
              window.showSuccessMessage(successMessage);
            } else {
              console.info(successMessage);
            }
          })
          .catch(err => {
            if (typeof window.showErrorMessage === 'function') {
              window.showErrorMessage('Failed to copy text: ' + err.message);
            } else {
              console.error('Failed to copy text: ', err);
            }
          });
      } else {
        const textarea = document.createElement('textarea');
        textarea.value = textToCopy;
        textarea.style.position = 'fixed';
        textarea.style.opacity = 0;
        document.body.appendChild(textarea);
        textarea.select();

        try {
          const success = document.execCommand('copy');
          if (success) {

            if (typeof window.showSuccessMessage === 'function') {
              window.showSuccessMessage(successMessage);
            } else {
              console.info(successMessage);
            }
          } else {
            if (typeof window.showErrorMessage === 'function') {
              window.showErrorMessage('Failed to copy text');
            } else {
              console.error('Failed to copy text');
            }
          }
        } catch (err) {
          if (typeof window.showErrorMessage === 'function') {
            window.showErrorMessage('Failed to copy text: ' + err.message);
          } else {
            console.error('Failed to copy text: ', err);
          }
        }

        document.body.removeChild(textarea);
      }
    };

    element.addEventListener('click', clickHandler);

    return () => {
      element.removeEventListener('click', clickHandler);
    };
  };

  /**
   * Initialize copy to clipboard functionality on multiple elements
   *
   * @param {string} selector - CSS selector to find elements
   * @param {Object} options - Options for the copy functionality
   * @return {Function} - Cleanup function to remove all event listeners
   */
  const initializeAll = (selector, options = {}) => {
    const elements = document.querySelectorAll(selector);
    const cleanupFunctions = [];

    elements.forEach(element => {
      const cleanup = initialize(element, options);
      cleanupFunctions.push(cleanup);
    });

    return () => {
      cleanupFunctions.forEach(cleanup => cleanup());
    };
  };

  return {
    initialize,
    initializeAll,
  };
};

export default useCopyToClipboard;
