import wretch from 'wretch';
import FormUrlAddon from "wretch/addons/formUrl";

const useForm = () => {
    const changeAccount = (url, idAccount) => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl({ id_account: idAccount })
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }
                reject(new Error('An error occurred while saving the account'));
            });
    });

    const changeTestMode = (url, idAccount, testMode) => new Promise((resolve, reject) => {
        wretch(url)
            .addon(FormUrlAddon)
            .formUrl({ id_account: idAccount, test_mode: testMode })
            .post()
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }
                reject(new Error('An error occurred while saving the account'));
            });
    });

    const formSubmit = (url, formData, idAccount, filesFormData = null) => new Promise((resolve, reject) => {
        if (filesFormData) {
            const searchParams = new URLSearchParams(formData);
            searchParams.append('id_account', idAccount);

            for (const [key, value] of searchParams) {
                filesFormData.append(key, value);
            }

            wretch(url)
                .post(filesFormData)
                .json(response => {
                    resolve(response);
                })
                .catch(response => {
                    if (response.error) {
                        reject(new Error(response.error));
                        return;
                    }
                    reject(new Error('An error occurred while saving the account'));
                });
        } else {
            wretch(url)
                .addon(FormUrlAddon)
                .formUrl(formData + `&id_account=${idAccount}`)
                .post()
                .json(response => {
                    resolve(response);
                })
                .catch(response => {
                    if (response.error) {
                        reject(new Error(response.error));
                        return;
                    }
                    reject(new Error('An error occurred while saving the account'));
                });
        }
    });

    const formSubmitFormData = (url, formData = {},) => new Promise((resolve, reject) => {
        wretch(url)
            .post(formData)
            .json(response => {
                resolve(response);
            })
            .catch(response => {
                if (response.error) {
                    reject(new Error(response.error));

                    return;
                }
                reject(new Error('An error occurred while saving the account'));
            });
    });

    const migrate = (url) => {
        window.location.href = url;
    };

    return {
        changeAccount,
        changeTestMode,
        formSubmit,
        formSubmitFormData,
        migrate,
    };
};

export default useForm;
