import useForm from '../components/useForm';
import useCopyToClipboard from '../components/useCopyToClipboard';

const DOM_SELECTORS = {
    PRZELEWY24_ORDER_REFUND_WRAPPER: '.js-przelewy-order-refund-wrapper',
    PRZELEWY24_ORDER_DETAILS: '.js-przelewy-order-details',
    PRZELEWY24_ORDER_REFUNDS: '.js-przelewy24-order-returns',
    PRZELEWY24_ORDER_REFUNDS_ITEM: '.p24_refund_row_product',
    PRZELEWY24_ORDER_REFUNDS_TOTAL: '#refund_total_refund',
    PRZELEWY24_ORDER_REFUNDS_EXTRA: '#refund_extra_refund',
    PRZELEWY24_ORDER_REFUNDS_SAVE: '#refund_save',
    PRZELEWY24_REPAYMENT_LINK: '.js-przelewy24-repayment-link',
};

const orderController = () => {

    const {
        formSubmitFormData,
    } = useForm();
    const { initializeAll } = useCopyToClipboard();
    const refundsForm = document.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS);

    const recalculateTotal = () => {
        if (refundsForm) {
            const refundsItems = refundsForm.querySelectorAll(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_ITEM);
            const totalRefund = refundsForm.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_TOTAL);
            const extraRefund = refundsForm.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_EXTRA);

            let total = 0;

            refundsItems.forEach((item) => {
                const quantity = parseInt(item.value);
                if (quantity > 0) {
                    const price = item.dataset.price;
                    total += parseInt(quantity, 10) * parseFloat(price);
                }
            });
            if (parseFloat(extraRefund.value) > 0) {
                total += parseFloat(extraRefund.value);
            }

            totalRefund.value = total.toFixed(2) > 0 ? total.toFixed(2) : '';
        }
    }

    const refundsItemsRecalculate = () => {
        const refundsItems = refundsForm.querySelectorAll(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_ITEM);
        refundsItems.forEach((item) => {
            item.addEventListener('change', (event) => {
                recalculateTotal();
            });
        });
    }

    const extraRefundRecalculate = () => {
        const extraRefund = document.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_EXTRA);
        if (extraRefund) {
            extraRefund.addEventListener('change', (event) => {
                recalculateTotal();
            });
        }
    }

    const saveRefundsAction = () => {
        const saveButton = document.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUNDS_SAVE);
        saveButton.addEventListener('click', async (event) => {
            event.preventDefault();
            const form = event.target.closest('form');
            const formData = new FormData(form);
            const url = form.action;

            try {
                const response = await formSubmitFormData(url, formData);

                if (response.success && response.history_payment_content && response.refund_form_content) {
                    window.showSuccessMessage(refundsForm.dataset.successMessage);

                    const detailswrapper = document.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_DETAILS);
                    detailswrapper.innerHTML = response.history_payment_content;

                    const refundsWrapper = document.querySelector(DOM_SELECTORS.PRZELEWY24_ORDER_REFUND_WRAPPER);
                    refundsWrapper.innerHTML = response.refund_form_content;

                    initEventsOnSave();
                }
            } catch (errorResponse) {
                if (errorResponse.error) {
                    console.log(errorResponse.error);
                    window.showErrorMessage(errorResponse.error);
                } else {
                    console.warn(errorResponse);
                    window.showErrorMessage(errorResponse);
                }
            }
        });
    }
    const initEventsOnSave = () => {
        refundsItemsRecalculate();
        extraRefundRecalculate();
        saveRefundsAction();
    }

    const initCopyToClipboard = () => {
        const repaymentLinks = document.querySelectorAll(DOM_SELECTORS.PRZELEWY24_REPAYMENT_LINK);
        if (repaymentLinks.length > 0) {
            initializeAll(DOM_SELECTORS.PRZELEWY24_REPAYMENT_LINK, {
                dataAttribute: 'data-repayment-link',
                successMessageAttribute: 'data-success-message',
                defaultSuccessMessage: 'Link copied to clipboard',
            });
        }
    };

    const init = () => {
        initCopyToClipboard();

        if (!refundsForm) {
            return;
        }
        initEventsOnSave();
    }

    return {
        init,
    };
}

export default orderController;
